/**
 * @summary Get optimal navigation path for a fan to a destination
 */
export const getGetFanNavigationUrl = (
  id: number,
  params: GetFanNavigationParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/fans/${id}/navigate?${stringifiedParams}`
    : `/api/fans/${id}/navigate`;
};

export const getFanNavigation = async (
  id: number,
  params: GetFanNavigationParams,
  options?: RequestInit,
): Promise<NavigationPath> => {
  return customFetch<NavigationPath>(getGetFanNavigationUrl(id, params), {
    ...options,
    method: "GET",
  });
};

